@import "../node_modules/bootstrap/scss/functions";
@import "../node_modules/bootstrap/scss/variables";
@import "../node_modules/bootstrap/scss/variables-dark";




// GLOBAL COLORS

$blue-oddo: #0189FE;
$dark-card: #161348;
$text-gray: #8f9bb3;

// Overwrite native labels of bootsrap

$primary: $blue-oddo;
$body-bg: #ffffff;
$body-color: #1A1941;

//borders and shadows
$border-radius: 0.5rem;
$border-radius-lg: 1.5rem;
$border-radius-xl: 3rem;
$box-shadow: 0 10px 30px #b9b9b9;


//merge colors whith bootstrap
$custom-theme: (
  "brand": $blue-oddo,
  "card-dark": $dark-card   
);
$theme-colors: map-merge($theme-colors, $custom-theme);


// PX
$custom-spacers : (
  6: $spacer * 4,
  7: $spacer * 5,
  8: $spacer * 6,
  9: $spacer * 8,
  10: $spacer * 10,

);

//merge px whith bootstrap
$spacers : map-merge($spacers , $custom-spacers);


@import "../node_modules/bootstrap/scss/bootstrap";

//global px 
.main-container{
  @extend .px-10;
}


//FOOTER
.footer-style{
   clip-path: polygon(0 5%, 100% 0, 100%, 0 100%);
}



.card-hover-lift{

  transition: transform 0.3s ease , box-shadow 0-3 ease;
}
.card-hover-lift:hover{
transform: translateY(-10px);
box-shadow: 0 1rem 3rem rgba(0 , 0, 0, .15) !important;
}
